INSERT INTO moderation_training_data (content, label, created_at)
SELECT 'kys|kms|kill yourself|go kill yourself', 'NEGATIVE', NOW()
WHERE NOT EXISTS (
    SELECT 1 FROM moderation_training_data WHERE content LIKE '%kys%'
);

